import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
@SuppressWarnings("serial")
public class FileServlet extends HttpServlet {
    public void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException{ 
        String fileName = request.getParameter("filename");   // Get the filename from URL parameter    
        
        if (fileName == null){      // If no name provided in url then return error message   
            response.setContentType("text/html;charset=utf-8"); 
            PrintWriter out = response.getWriter();      
            
            String htmlResponse =  "<h1>Error: No file specified! <a href='index.html'>Back to main page...</a></h1>";   // HTML error message   
                                                                                                                      
            out.println(htmlResponse); 
        } else {    
             String contentType = getServletContext().getMimeType(fileName);      // Get the file's MIME type from context (servlet)      
              if (contentType == null){    // If no specific mimetype found, default to binary  
                  contentType="application/octet-stream"; 
             }    
            response.setContentType(contentType);      // Set the MIME type of file's data as a header value      
             
          try (ServletOutputStream out = response.getOutputStream()) {    // Get an output stream to write into  
                String path= getServletContext().getRealPath("/uploads/"+fileName);  //Get absolute Path from context and append filename     
             File file  = new File(path);    
              if(!file.exists()){       // If the requested resource does not exist, return error message  
                  response.setContentType("text/html;charset=utf-8");   
                 PrintWriter out1 =response .getWriter(); 
                   String htmlResponse =  "<h2>Error: File Not Found! <a href='index.html'>Back to main page...</a><\/\h2>";   // HTML error message    
                  out1.println(htmlResponse);   
              } else {     
                 response.setContentLengthLong(file.length());  // Set the file length as a header value      
                  
                try (FileInputStream fis = new FileInputStream(file)) {        // Get an input stream to read from  
                      IOUtils.copy(fis, out);     // Copy contents of uploaded files into response's outputstream     
                 } 
              }   
          } catch (Exception e) {       // Catch any exception that may occur during file handling process and print error message       
             throw new ServletException(e);  
         }}          
     }           
}